var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"탄탄하게 다져진 몸매, 의뢰인 보다 큰 키, 도도하면서도 세련된 분위기.","JPN":"がっちりした体つき、依頼人より高い背、おしゃれでクールな感じ。","ENG":"A strong, fit body. Taller than our client. Looks aloof and unapproachable on the outside.","TWN":"身材好，個子比委託人高，帶有孤傲高尚的氣場。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"거의 완벽하군요. 몇 가지만 더 확인하면 되겠어요.","JPN":"ほぼ完璧ですね。あと、いくつか確認すればいいだけです。","ENG":"She's almost perfect. We just need to check a couple of more things.","TWN":"近乎完美呢，只需要再確認一兩個條件就可以了。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"실례지만 혹시 귀하의 사회적인 지위가 어느 정도인지 여쭤봐도 되겠습니까?","JPN":"失礼ですが、あなたの社会的地位がどれくらいなのか、お伺いしてもよろしいですか？","ENG":"I'm sorry, but may I ask how successful you are socially?","TWN":"我可以冒昧地問一下閣下的社會地位嗎？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"네? 저요? 하하, 제 입으로 말하긴 좀 부끄럽지만 이래봬도 저희 세계에서는 좀 알아주는 최고급 용병이긴 하죠.","JPN":"はい？　私ですか？　ハハ、自分で言うのも恥ずかしいですが、\\nこれでも私が住む世界ではなかなか有名な最高ランクの傭兵なんです。","ENG":"Pardon? Me? Hah hah. I don't want to brag, but I am a first-class mercenary in my world.","TWN":"嗯？我嗎？哈哈，自己說會有點不好意思啦，但別看我這樣，我在我們世界裡可是受到世人認可的頂尖傭兵喔。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"정부 기관 의뢰도 받는 입장이거든요. 엣헴!","JPN":"政府機関から依頼を受けたりもします。えっへん！","ENG":"I even get jobs from governmental agencies. Ahem!","TWN":"還會收到政府機關的委託呢，欸嘿！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 낯선 이의 질문에도 자세히 답해주는 저 상냥함!","JPN":"ふふ、見知らぬ者の質問にも詳しく答えてくれるその優しさ！","ENG":"Hah hah. She's also kind enough to answer strangers' questions!","TWN":"呵呵，對陌生人的提問也予以詳盡的解答，何等溫柔！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"의뢰는 성공적인 것 같군요. 아주 잘 어울리는 한 쌍이 될 것 같네요.","JPN":"依頼は成功したようですね。とてもお似合いのカップルになりそうです。","ENG":"Mission accomplished! You'll make a wonderful couple.","TWN":"委託圓滿地解決了，你們看起來非常相配呢。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"다...... 다......","JPN":"あ……あ……","ENG":"Ah... Ah...","TWN":"你……你……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"왜 그러시죠? 너무 기뻐서 말문이 막히셨나요, 고객님?","JPN":"どうしましたか？　嬉しすぎて言葉を失いましたか、お客様？","ENG":"What’s wrong? Let me guess. You're choking on happiness, aren't you?","TWN":"您怎麼了？您是因為太高興，所以說不出話來了嗎，客人？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"당신 장님이죠?!! 결정적인 문제가 있잖아!!","JPN":"あなた目が見えないんですか？　決定的な問題があるじゃないですか！","ENG":"Are you blind? Can't you see the problem?","TWN":"你眼瞎了嗎？！！有個決定性的問題吧！！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"저쪽은 여자라고! 여자!!","JPN":"あの人は女の人です！　女の！！","ENG":"She's a girl! A girl!","TWN":"她是個女的！女的！！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"네? 딱히 성별에 대한 조건은 없었던 것 같습니다만?","JPN":"はい？　特に性別についての条件はなかったようですが？","ENG":"Pardon? But you didn't specify the sex.","TWN":"嗯？我記得妳在性別方面沒有特別要求呀？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"무슨 문제라도 있습니까?","JPN":"何か問題でもありますか？","ENG":"Is that a problem?","TWN":"有什麼問題嗎？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"당연히 큰 문제가 있지! 난 남자가 취향이라고!","JPN":"もちろん大問題です！　私は男の人がよかったんです！","ENG":"Yes, it is! I like men!","TWN":"問題很大好嗎！我喜歡男的！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"하하...... 그나저나 저도 궁금한 게 있는데 대체 여기가 어딜까요?","JPN":"ハハ……ところで、私も気になることがあるんですが、ここはいったいどこでしょう？","ENG":"Hah hah... I've got a question, too. Where is this place?","TWN":"哈哈……那個，我有件好奇的事情，我現在到底在什麼地方？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"갑자기 눈 앞이 번쩍하더니...... 여기로 떨어진 것 같은데.","JPN":"急に目の前が光って……ここに落ちたみたいですが。","ENG":"One moment I saw a sudden flash of light, and the next I was here.","TWN":"我眼前好像突然一閃……然後就來到這個地方了。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROSARIA_FALLEN_SUMMER_NULL","text":{"KOREA":"흠, 간단히 설명하면 저 음침한 처녀를 위한 운명의 상대를 불러냈더니 네가 튀어나온 상황이지.","JPN":"ふん、簡単に説明すると、あの陰気な乙女のために運命の相手を呼び出したら、其方が飛び出てきたといった状況じゃ。","ENG":"Hm, to cut a long story short, this gloomy maiden here summoned her soul mate, and you popped out.","TWN":"嗯，簡單說明的話，我為那個陰沉的女孩召喚了命運之人，結果妳就蹦出來了。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"아하, 그렇군요!","JPN":"あ、そういうことですか！","ENG":"Aha, I see!","TWN":"啊哈，原來如此！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};